-- Static executive demo: SL curves + FTE / TL / performance wallboard JSON (single row config)

CREATE TABLE IF NOT EXISTS executive_sl_curves (
  client_scope text PRIMARY KEY CHECK (client_scope IN ('all', 'client-a', 'client-b')),
  points jsonb NOT NULL
);

CREATE TABLE IF NOT EXISTS executive_demo_config (
  id int PRIMARY KEY DEFAULT 1 CHECK (id = 1),
  fte_teams jsonb NOT NULL,
  tl_scores jsonb NOT NULL,
  perf_live_stats jsonb NOT NULL,
  updated_at timestamptz DEFAULT now()
);

ALTER TABLE executive_sl_curves ENABLE ROW LEVEL SECURITY;
ALTER TABLE executive_demo_config ENABLE ROW LEVEL SECURITY;
DROP POLICY IF EXISTS "executive_sl_read" ON executive_sl_curves;
CREATE POLICY "executive_sl_read" ON executive_sl_curves FOR SELECT TO authenticated USING (true);
DROP POLICY IF EXISTS "executive_demo_cfg_read" ON executive_demo_config;
CREATE POLICY "executive_demo_cfg_read" ON executive_demo_config FOR SELECT TO authenticated USING (true);

